const codes = {"Java": "<span class=\"kw\">interface</span> <span class=\"cl\">Renderer</span> {\n  <span class=\"cl\">String</span> <span class=\"fn\">render</span>(<span class=\"cl\">String</span> <span class=\"dc\">shape</span>);\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">VectorRenderer</span> <span class=\"kw\">implements</span> <span class=\"cl\">Renderer</span> {\n  <span class=\"kw\">public</span> <span class=\"cl\">String</span> <span class=\"fn\">render</span>(<span class=\"cl\">String</span> <span class=\"dc\">s</span>) {\n    <span class=\"kw\">return</span> <span class=\"st\">\"Vector: \"</span> + <span class=\"dc\">s</span>;\n  }\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">RasterRenderer</span> <span class=\"kw\">implements</span> <span class=\"cl\">Renderer</span> {\n  <span class=\"kw\">public</span> <span class=\"cl\">String</span> <span class=\"fn\">render</span>(<span class=\"cl\">String</span> <span class=\"dc\">s</span>) {\n    <span class=\"kw\">return</span> <span class=\"st\">\"Raster: \"</span> + <span class=\"dc\">s</span>;\n  }\n}\n\n<span class=\"kw\">abstract class</span> <span class=\"cl\">Shape</span> {\n  <span class=\"kw\">protected final</span> <span class=\"cl\">Renderer</span> <span class=\"dc\">renderer</span>;\n  <span class=\"fn\">Shape</span>(<span class=\"cl\">Renderer</span> <span class=\"dc\">r</span>) { <span class=\"dc\">this</span>.<span class=\"dc\">renderer</span> = <span class=\"dc\">r</span>; }\n  <span class=\"kw\">abstract</span> <span class=\"cl\">String</span> <span class=\"fn\">draw</span>();\n}\n\n<span class=\"kw\">class</span> <span class=\"cl\">Circle</span> <span class=\"kw\">extends</span> <span class=\"cl\">Shape</span> {\n  <span class=\"fn\">Circle</span>(<span class=\"cl\">Renderer</span> <span class=\"dc\">r</span>) { <span class=\"kw\">super</span>(<span class=\"dc\">r</span>); }\n  <span class=\"cl\">String</span> <span class=\"fn\">draw</span>() { <span class=\"kw\">return</span> <span class=\"dc\">renderer</span>.<span class=\"fn\">render</span>(<span class=\"st\">\"circle\"</span>); }\n}", "CSharp": "<span class=\"kw\">public interface</span> <span class=\"cl\">IRenderer</span> {\n  <span class=\"kw\">string</span> <span class=\"fn\">Render</span>(<span class=\"kw\">string</span> <span class=\"dc\">s</span>);\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">VectorRenderer</span> : <span class=\"cl\">IRenderer</span> {\n  <span class=\"kw\">public string</span> <span class=\"fn\">Render</span>(<span class=\"kw\">string</span> <span class=\"dc\">s</span>) =&gt; <span class=\"st\">$\"Vector: {{s}}\"</span>;\n}\n\n<span class=\"kw\">public abstract class</span> <span class=\"cl\">Shape</span>(<span class=\"cl\">IRenderer</span> <span class=\"dc\">r</span>) {\n  <span class=\"kw\">public abstract string</span> <span class=\"fn\">Draw</span>();\n}\n\n<span class=\"kw\">public class</span> <span class=\"cl\">Circle</span>(<span class=\"cl\">IRenderer</span> <span class=\"dc\">r</span>) : <span class=\"cl\">Shape</span>(<span class=\"dc\">r</span>) {\n  <span class=\"kw\">public override string</span> <span class=\"fn\">Draw</span>() =&gt; <span class=\"dc\">r</span>.<span class=\"fn\">Render</span>(<span class=\"st\">\"circle\"</span>);\n}\n\n<span class=\"cm\">// new Circle(new VectorRenderer()).Draw()  \u2192  \"Vector: circle\"</span>", "Python": "<span class=\"kw\">class</span> <span class=\"cl\">VectorRenderer</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">render</span>(<span class=\"dc\">self</span>, <span class=\"dc\">s</span>): <span class=\"kw\">return</span> <span class=\"st\">f\"Vector: {{s}}\"</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">RasterRenderer</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">render</span>(<span class=\"dc\">self</span>, <span class=\"dc\">s</span>): <span class=\"kw\">return</span> <span class=\"st\">f\"Raster: {{s}}\"</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">Shape</span>:\n  <span class=\"kw\">def</span> <span class=\"fn\">__init__</span>(<span class=\"dc\">self</span>, <span class=\"dc\">r</span>): <span class=\"dc\">self.r</span> = <span class=\"dc\">r</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">draw</span>(<span class=\"dc\">self</span>): <span class=\"kw\">raise</span> <span class=\"cl\">NotImplementedError</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">Circle</span>(<span class=\"cl\">Shape</span>):\n  <span class=\"kw\">def</span> <span class=\"fn\">draw</span>(<span class=\"dc\">self</span>): <span class=\"kw\">return</span> <span class=\"dc\">self.r</span>.<span class=\"fn\">render</span>(<span class=\"st\">\"circle\"</span>)\n\n<span class=\"cm\"># Circle(VectorRenderer()).draw()  \u2192  \"Vector: circle\"</span>", "Ruby": "<span class=\"kw\">class</span> <span class=\"cl\">Shape</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">initialize</span>(<span class=\"dc\">r</span>) = <span class=\"dc\">@r</span> = <span class=\"dc\">r</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">draw</span> = <span class=\"kw\">raise</span> <span class=\"cl\">NotImplementedError</span>\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">Circle</span> &lt; <span class=\"cl\">Shape</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">draw</span> = <span class=\"dc\">@r</span>.<span class=\"fn\">render</span>(<span class=\"st\">\"circle\"</span>)\n<span class=\"kw\">end</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">VectorRenderer</span>\n  <span class=\"kw\">def</span> <span class=\"fn\">render</span>(<span class=\"dc\">s</span>) = <span class=\"st\">\"Vector: #{{s}}\"</span>\n<span class=\"kw\">end</span>\n\n<span class=\"cm\"># Circle.new(VectorRenderer.new).draw  \u2192  \"Vector: circle\"</span>"}

